#include <bits/stdc++.h>
using namespace std;


int maximalSquare(vector<vector<int>>& mat) {

    int m = mat.size(), n = mat[0].size(), maxside = 0;
    vector<vector<int>> dp(m, vector<int>(n, 0));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (!i || !j || mat[i][j] == 0) {
                dp[i][j] = mat[i][j];
            } else {
                dp[i][j] = 1 + min(dp[i - 1][j - 1], min(dp[i - 1][j], dp[i][j - 1]));
            }
            maxside = max(maxside, dp[i][j]);
        }
    }
    return maxside * maxside;
}


int main() {

  int n, m;
  cin >> n;

  assert(1 <= n && n <= 100);

  vector<vector<int> > mat(n, vector<int> (n));
  for(int i = 0; i < n; i++){
    for(int j = 0; j < n; j++){
        cin >> mat[i][j];
        assert(mat[i][j] == 0 || mat[i][j] == 1);
    }
  } 

  cout << maximalSquare(mat);


  return 0;
}

